package planning

// Golden tests for the planning prompt builders. Each expected value is the
// exact UTF-8 output of the corresponding Python reference function (from
// swe_af/prompts/*.py), captured as base64 and decoded here — so the assertions
// are independent of how the Go string literals were encoded.

import (
	"encoding/base64"
	"testing"

	"github.com/Agent-Field/SWE-AF/go/internal/schemas"
)

// golden maps a case name to the base64 of the exact Python output.
var golden = map[string]string{
	"arch_system":           "",
	"arch_task_fb":          "",
	"arch_task_nofb":        "",
	"arch_taskprompt_multi": "",
	"es_system":             "",
	"es_task_pass1":         "",
	"es_task_pass1_multi":   "",
	"es_task_pass2":         "",
	"es_task_sample_svc":    "",
	"fpur_empty":            "",
	"fpur_one":              "",
	"kssp_all":              "",
	"kssp_sample":           "",
	"pm_system":             "",
	"pm_task_ctx":           "",
	"pm_task_noctx":         "",
	"pm_task_prior":         "",
	"pm_taskprompt_multi":   "",
	"pm_taskprompt_single":  "",
	"sp_system":             "",
	"sp_task":               "",
	"sp_taskprompt_min":     "",
	"sp_taskprompt_multi":   "",
	"sp_taskprompt_single":  "",
	"tl_system":             "",
	"tl_task_rev0":          "",
	"tl_task_rev2":          "",
	"tl_taskprompt_multi":   "",
	"ws_multi":              "IyMgV29ya3NwYWNlIFJlcG9zaXRvcmllcwoKVGhpcyB0YXNrIHNwYW5zIG11bHRpcGxlIHJlcG9zaXRvcmllcy4gRWFjaCByZXBvc2l0b3J5IGlzIGxpc3RlZCBiZWxvdyB3aXRoIGl0cyByb2xlIGFuZCBsb2NhbCBwYXRoOgoKLSAqKmFwaSoqIChyb2xlOiBwcmltYXJ5KTogYC90bXAvYXBpYAotICoqbGliKiogKHJvbGU6IGRlcGVuZGVuY3kpOiBgL3RtcC9saWJgCg==",
	"ws_none":               "",
	"ws_single":             "",
}

func want(t *testing.T, key string) string {
	t.Helper()
	enc, ok := golden[key]
	if !ok {
		t.Fatalf("no golden entry for %q", key)
	}
	b, err := base64.StdEncoding.DecodeString(enc)
	if err != nil {
		t.Fatalf("decode golden %q: %v", key, err)
	}
	return string(b)
}

func eq(t *testing.T, key, got string) {
	t.Helper()
	w := want(t, key)
	if got != w {
		t.Errorf("%s mismatch:\n--- got  (%d bytes) ---\n%q\n--- want (%d bytes) ---\n%q",
			key, len(got), got, len(w), w)
	}
}

// --- shared fixtures (mirror gen_golden.py) ---

func repo(name, role, path string, createPR bool) schemas.WorkspaceRepo {
	return schemas.WorkspaceRepo{
		RepoName:     name,
		RepoURL:      "https://github.com/org/x.git",
		Role:         role,
		AbsolutePath: path,
		Branch:       "main",
		SparsePaths:  []string{},
		CreatePR:     createPR,
	}
}

func singleManifest() *schemas.WorkspaceManifest {
	return &schemas.WorkspaceManifest{
		WorkspaceRoot:   "/tmp",
		Repos:           []schemas.WorkspaceRepo{repo("a", "primary", "/tmp/a", true)},
		PrimaryRepoName: "a",
	}
}

func multiManifest() *schemas.WorkspaceManifest {
	return &schemas.WorkspaceManifest{
		WorkspaceRoot: "/tmp",
		Repos: []schemas.WorkspaceRepo{
			repo("api", "primary", "/tmp/api", true),
			repo("lib", "dependency", "/tmp/lib", false),
		},
		PrimaryRepoName: "api",
	}
}

