// --- system prompt constants (a) equal the Python text ---

func TestSystemPromptConstants(t *testing.T) {
	eq(t, "pm_system", PMSystemPrompt)
	eq(t, "arch_system", ArchitectSystemPrompt)
	eq(t, "tl_system", TechLeadSystemPrompt)
	eq(t, "sp_system", SprintPlannerSystemPrompt)
	eq(t, "es_system", EnvironmentScoutSystemPrompt)
}

// --- workspace_context_block behavioral assertions (ported from
// tests/test_workspace_context_block.py) ---

func TestWorkspaceContextBlock(t *testing.T) {
	// AC-14: nil manifest returns empty string, no panic.
	if got := WorkspaceContextBlock(nil); got != "" {
		t.Errorf("nil manifest = %q, want \"\"", got)
	}
	// Single-repo returns empty string.
	if got := WorkspaceContextBlock(singleManifest()); got != "" {
		t.Errorf("single manifest = %q, want \"\"", got)
	}
	// Zero repos returns empty string.
	zero := &schemas.WorkspaceManifest{WorkspaceRoot: "/tmp", Repos: []schemas.WorkspaceRepo{}, PrimaryRepoName: ""}
	if got := WorkspaceContextBlock(zero); got != "" {
		t.Errorf("zero-repo manifest = %q, want \"\"", got)
	}
	// AC-15: multi-repo returns non-empty containing names, paths, roles.
	got := WorkspaceContextBlock(multiManifest())
	if got == "" {
		t.Fatal("multi manifest returned empty string")
	}
	for _, sub := range []string{"api", "lib", "/tmp/api", "/tmp/lib", "primary", "dependency"} {
		if !contains(got, sub) {
			t.Errorf("multi block missing %q", sub)
		}
	}
	// Byte-exact against Python.
	eq(t, "ws_none", WorkspaceContextBlock(nil))
	eq(t, "ws_single", WorkspaceContextBlock(singleManifest()))
	eq(t, "ws_multi", WorkspaceContextBlock(multiManifest()))
}

func contains(s, sub string) bool {
	for i := 0; i+len(sub) <= len(s); i++ {
		if s[i:i+len(sub)] == sub {
			return true
		}
	}
	return false
}

