// --- product manager (b) rendered task prompts ---

func TestProductManagerPrompts(t *testing.T) {
	_, task := ProductManagerPrompts(ProductManagerPromptsOpts{
		Goal: "Add dark mode", RepoPath: "/repo", PRDPath: "/plan/prd.md",
		AdditionalContext: "Use CSS vars",
	})
	eq(t, "pm_task_ctx", task)

	_, task2 := ProductManagerPrompts(ProductManagerPromptsOpts{
		Goal: "Add dark mode", RepoPath: "/repo", PRDPath: "/plan/prd.md",
	})
	eq(t, "pm_task_noctx", task2)

	_, task3 := ProductManagerPrompts(ProductManagerPromptsOpts{
		Goal: "Add dark mode", RepoPath: "/repo", PRDPath: "/plan/prd.md",
		AdditionalContext: "Use CSS vars", PriorUserResponses: priorResponses(),
	})
	eq(t, "pm_task_prior", task3)

	eq(t, "pm_taskprompt_multi", PMTaskPrompt(PMTaskPromptOpts{
		Goal: "Add dark mode", RepoPath: "/repo", PRDPath: "/plan/prd.md",
		AdditionalContext: "Use CSS vars", WorkspaceManifest: multiManifest(),
	}))
	eq(t, "pm_taskprompt_single", PMTaskPrompt(PMTaskPromptOpts{
		Goal: "Add dark mode", RepoPath: "/repo", PRDPath: "/plan/prd.md",
		WorkspaceManifest: singleManifest(),
	}))
}

// --- architect ---

func TestArchitectPrompts(t *testing.T) {
	prd := samplePRD()
	_, task := ArchitectPrompts(ArchitectPromptsOpts{
		PRD: prd, RepoPath: "/repo", PRDPath: "/plan/prd.md", ArchitecturePath: "/plan/arch.md",
	})
	eq(t, "arch_task_nofb", task)

	_, taskfb := ArchitectPrompts(ArchitectPromptsOpts{
		PRD: prd, RepoPath: "/repo", PRDPath: "/plan/prd.md", ArchitecturePath: "/plan/arch.md",
		Feedback: "Fix the error model",
	})
	eq(t, "arch_task_fb", taskfb)

	eq(t, "arch_taskprompt_multi", ArchitectTaskPrompt(ArchitectTaskPromptOpts{
		PRD: prd, RepoPath: "/repo", PRDPath: "/plan/prd.md", ArchitecturePath: "/plan/arch.md",
		Feedback: "Fix the error model", WorkspaceManifest: multiManifest(),
	}))
}

