// --- sprint planner ---

func TestSprintPlannerPrompts(t *testing.T) {
	prd := samplePRD()
	arch := schemas.Architecture{
		Summary: "Layered lexer/parser", Components: nil, Interfaces: nil,
		Decisions: nil, FileChangesOverview: "",
	}
	_, task := SprintPlannerPrompts(SprintPlannerPromptsOpts{
		PRD: prd, Architecture: arch, RepoPath: "/repo",
		PRDPath: "/plan/prd.md", ArchitecturePath: "/plan/arch.md",
	})
	eq(t, "sp_task", task)

	prdDict := map[string]any{
		"validated_description": "Build a lexer",
		"acceptance_criteria":   []any{"AC1 works", "AC2 works"},
	}
	archDict := map[string]any{"summary": "Layered lexer/parser"}

	eq(t, "sp_taskprompt_multi", SprintPlannerTaskPrompt(SprintPlannerTaskPromptOpts{
		Goal: "Build lexer", PRD: prdDict, Architecture: archDict,
		WorkspaceManifest: multiManifest(), RepoPath: "/repo",
		PRDPath: "/plan/prd.md", ArchitecturePath: "/plan/arch.md",
	}))
	eq(t, "sp_taskprompt_single", SprintPlannerTaskPrompt(SprintPlannerTaskPromptOpts{
		Goal: "Build lexer", PRD: prdDict, Architecture: archDict,
		WorkspaceManifest: singleManifest(), RepoPath: "/repo",
		PRDPath: "/plan/prd.md", ArchitecturePath: "/plan/arch.md",
	}))
	eq(t, "sp_taskprompt_min", SprintPlannerTaskPrompt(SprintPlannerTaskPromptOpts{
		Goal: "Build lexer", PRD: map[string]any{}, Architecture: map[string]any{},
	}))
}

// --- environment scout ---

func TestEnvironmentScoutTaskPrompt(t *testing.T) {
	prd := map[string]any{
		"validated_description": "Add a Sentry alerting rule",
		"must_have":             []any{"new alert", "release tracking"},
		"nice_to_have":          []any{"dashboards"},
		"acceptance_criteria":   []any{"alert fires on error"},
	}
	eq(t, "es_task_pass1", EnvironmentScoutTaskPrompt(EnvironmentScoutTaskPromptOpts{
		PRD: prd, RepoPath: "/repo",
	}))
	eq(t, "es_task_pass1_multi", EnvironmentScoutTaskPrompt(EnvironmentScoutTaskPromptOpts{
		PRD: prd, RepoPath: "/repo", WorkspaceManifest: multiManifest(),
	}))
	eq(t, "es_task_pass2", EnvironmentScoutTaskPrompt(EnvironmentScoutTaskPromptOpts{
		PRD: prd, RepoPath: "/repo", PriorUserResponses: priorResponses(),
	}))
	eq(t, "es_task_sample_svc", EnvironmentScoutTaskPrompt(EnvironmentScoutTaskPromptOpts{
		PRD: map[string]any{"validated_description": "x"}, RepoPath: "/repo",
		KnownServices: sampleServices(),
	}))
}
